      usptoFee=Math.round(320*d);
      issueFee=0;
      timeline='12 months to file non-provisional';
    } else if(type==='utility'){
      var filing=Math.round(320*d);
      var search=Math.round(700*d);
      var exam=Math.round(800*d);
      var excessClaims=Math.max(0,claims-20)*Math.round(100*d);
