  var avgROI={kitchen_minor:0.77,kitchen_major:0.54,bath_minor:0.68,bath_major:0.55,deck:0.65,garage_door:0.94,siding:0.68,window:0.67,roof:0.61,basement:0.62,addition:0.53};
