    for(var i=0;i<50;i++){
      var mid=(lo+hi)/2;
      var loan=mid-down;
      if(loan<=0){maxPrice=mid;lo=mid;continue}
      var pi=loan*(r*Math.pow(1+r,n))/(Math.pow(1+r,n)-1);
      var tax=mid*(taxRate/100)/12;
      var pmi=down/mid<0.2?loan*0.007/12:0;
      var total=pi+tax+monthlyInsurance+pmi;
      if(total<=availableForHousing){lo=mid;maxPrice=mid}
      else{hi=mid}
    }

    var conservativePrice=maxPrice*0.85;
    var loanAmt=maxPrice-down;
    var pi=loanAmt>0?loanAmt*(r*Math.pow(1+r,n))/(Math.pow(1+r,n)-1):0;
    var monthlyTax=maxPrice*(taxRate/100)/12;
    var pmi=down/maxPrice<0.2?loanAmt*0.007/12:0;
    var totalPayment=pi+monthlyTax+monthlyInsurance+pmi;

