(function(){
  'use strict';
  function $(id){return document.getElementById(id)}
  function fmt(n){return Math.round(n).toString().replace(/\B(?=(\d{3})+(?!\d))/g,',')}

  $('calcBtn').addEventListener('click',function(){
    var pop=parseFloat($('pgPop').value)||500000;
    var rate=parseFloat($('pgRate').value)||1.5;
    var years=parseInt($('pgYears').value)||25;
    var capacity=parseFloat($('pgCapacity').value)||0;

    var r=rate/100;
    var projected,tenYear,model;

    if(capacity>0&&capacity>pop){
      // Logistic growth: P(t) = K / (1 + ((K-P0)/P0)*e^(-rt))
      var factor=(capacity-pop)/pop;
      projected=capacity/(1+factor*Math.exp(-r*years));
      tenYear=capacity/(1+factor*Math.exp(-r*Math.min(10,years)));
      model='Logistic (cap: '+fmt(capacity)+')';
    } else {
      projected=pop*Math.pow(1+r,years);
      tenYear=pop*Math.pow(1+r,Math.min(10,years));
      model='Exponential';
    }

    var growthPct=((projected-pop)/pop*100);
    var added=projected-pop;
    var doubling=r>0?Math.log(2)/Math.log(1+r):r<0?'N/A (declining)':'N/A (no growth)';
    var doublingStr=typeof doubling==='number'?doubling.toFixed(1)+' years':doubling;

    $('rProjected').textContent=fmt(projected);
    $('rGrowth').textContent=(growthPct>0?'+':'')+growthPct.toFixed(1)+'%';
    $('rGrowth').style.color=growthPct>0?'#16a34a':growthPct<0?'#dc2626':'inherit';
    $('rDoubling').textContent=doublingStr;
    $('rAdded').textContent=(added>0?'+':'')+fmt(added);
    $('rTenYear').textContent=fmt(tenYear);
    $('rModel').textContent=model;
    $('rModel').style.fontSize='0.85rem';
    $('result').classList.add('visible');
    $('result').style.display='block';
  });

  ['pgPop','pgRate','pgYears','pgCapacity'].forEach(function(id){
    $(id).addEventListener('keydown',function(e){if(e.key==='Enter')$('calcBtn').click()});
  });
})();

