(function(){
  'use strict';
  function $(id){return document.getElementById(id)}
  function money(n){return '$'+n.toFixed(0).replace(/\B(?=(\d{3})+(?!\d))/g,',')}

  function fedTax(income){
    var brackets=[[11600,0.10],[47150,0.12],[100525,0.22],[191950,0.24],[243725,0.32],[609350,0.35],[Infinity,0.37]];
    var tax=0,prev=0;
    for(var i=0;i<brackets.length;i++){
      var top=brackets[i][0],rate=brackets[i][1];
      var taxable=Math.min(income,top)-prev;
      if(taxable<=0)break;
      tax+=taxable*rate;
      prev=top;
    }
    return tax;
  }

  $('calcBtn').addEventListener('click',function(){
    var salA=parseFloat($('scSalaryA').value)||0;
    var colA=parseFloat($('scCOLA').value)||100;
    var taxA=parseFloat($('scTaxA').value)||0;
    var salB=parseFloat($('scSalaryB').value)||0;
    var colB=parseFloat($('scCOLB').value)||100;
    var taxB=parseFloat($('scTaxB').value)||0;

    var realA=salA/(colA/100);
    var realB=salB/(colB/100);

    var ficaA=Math.min(salA,168600)*0.0765;
    var ficaB=Math.min(salB,168600)*0.0765;
    var afterA=salA-fedTax(salA)-salA*(taxA/100)-ficaA;
    var afterB=salB-fedTax(salB)-salB*(taxB/100)-ficaB;

    var realAfterA=afterA/(colA/100);
    var realAfterB=afterB/(colB/100);

    var winner=realAfterA>realAfterB?'Location A':'Location B';
    var advantage=Math.abs(realAfterA-realAfterB);

    $('rRealA').textContent=money(realA);
    $('rRealB').textContent=money(realB);
    $('rAfterA').textContent=money(afterA);
    $('rAfterB').textContent=money(afterB);
    $('rWinner').textContent=winner;
    $('rWinner').style.color='#16a34a';
    $('rAdvantage').textContent='+'+money(advantage)+'/yr (real)';
    $('rAdvantage').style.fontSize='0.85rem';
    $('result').classList.add('visible');
    $('result').style.display='block';
  });

  ['scSalaryA','scCOLA','scTaxA','scSalaryB','scCOLB','scTaxB'].forEach(function(id){
    $(id).addEventListener('keydown',function(e){if(e.key==='Enter')$('calcBtn').click()});
  });
})();

